/*
 * OpenMP Tasking Example - Processing multiple independent tasks
 * Compile: gcc -fopenmp tasking_example.c -o tasking_example
 */
#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

// Function to process a single task (simulates independent work)
void process_image(int image_id) {
 printf("Thread %d processing image %d\n", omp_get_thread_num(), image_id);
 // Simulate computation
 for (volatile int i = 0; i < 1000000; i++);
}

// Recursive task example - like tree traversal or divide-and-conquer
void recursive_task(int depth, int max_depth) {
 if (depth >= max_depth) {
 printf("Thread %d: Reached leaf at depth %d\n", omp_get_thread_num(), depth);
 return;
 }

 // Create child tasks - each thread can execute these
 #pragma omp task
 recursive_task(depth + 1, max_depth);

 #pragma omp task
 recursive_task(depth + 1, max_depth);

 // Wait for child tasks before returning
 #pragma omp taskwait
}

int main() {
 printf("=== OpenMP Tasking Demo ===\n\n");

 // Example 1: Basic task creation
 printf("Example 1: Creating tasks within parallel region\n");
 #pragma omp parallel
 {
 // Only one thread should create tasks (prevents duplicates)
 #pragma omp single
 {
 #pragma omp task
 process_image(1); // Task A

 #pragma omp task
 process_image(2); // Task B

 #pragma omp task
 process_image(3); // Task C
 }

 // Wait for all child tasks to complete
 #pragma omp taskwait
 }

 printf("\nAll tasks completed!\n\n");

 // Example 2: Recursive task creation (tree structure)
 printf("Example 2: Recursive task creation (depth=3 tree)\n");
 #pragma omp parallel
 {
 #pragma omp single
 {
 recursive_task(0, 3);
 }
 }

 printf("\nRecursive tasks completed!\n");

 return 0;
}

/*
 * Task-Based Parallelism in Java using CompletableFuture
 * Demonstrates concepts similar to OpenMP #pragma omp task
 */
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.stream.Collectors;

public class TaskingExample {

 // Simulates processing work (like processing a task)
 public static String processTask(int taskId) {
 String threadName = Thread.currentThread().getName();
 System.out.println("Thread " + threadName + " processing task " + taskId);

 // Simulate computation
 try {
 Thread.sleep(100);
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }

 return "Result_" + taskId;
 }

 // Recursive task creation (like tree traversal with tasks)
 public static CompletableFuture<Void> createRecursiveTasks(int depth, int maxDepth) {
 if (depth >= maxDepth) {
 System.out.println("Thread " + Thread.currentThread().getName() + 
 " reached leaf at depth " + depth);
 return CompletableFuture.completedFuture(null);
 }

 // Create child tasks (like #pragma omp task)
 CompletableFuture<Void> task1 = CompletableFuture.runAsync(
 () -> createRecursiveTasks(depth + 1, maxDepth).join()
 );

 CompletableFuture<Void> task2 = CompletableFuture.runAsync(
 () -> createRecursiveTasks(depth + 1, maxDepth).join()
 );

 // Wait for both tasks (like #pragma omp taskwait)
 return CompletableFuture.allOf(task1, task2);
 }

 public static void main(String[] args) throws Exception {
 System.out.println("=== Java Task-Based Parallelism Demo ===\n");

 // Example 1: Basic task creation
 System.out.println("Example 1: Creating tasks with CompletableFuture\n");

 List<CompletableFuture<String>> futures = new ArrayList<>();

 // Create tasks dynamically (similar to #pragma omp task)
 for (int i = 1; i <= 4; i++) {
 final int taskId = i;
 CompletableFuture<String> future = CompletableFuture.supplyAsync(
 () -> processTask(taskId)
 );
 futures.add(future);
 }

 // Wait for all tasks to complete (like #pragma omp taskwait)
 CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();

 // Collect results
 List<String> results = futures.stream()
 .map(CompletableFuture::join)
 .collect(Collectors.toList());

 System.out.println("\nAll tasks completed! Results: " + results);

 // Example 2: Recursive task creation
 System.out.println("\n\nExample 2: Recursive task creation (depth=3)\n");
 CompletableFuture<Void> recursiveFuture = createRecursiveTasks(0, 3);
 recursiveFuture.join();

 System.out.println("\nRecursive tasks completed!");
 }
}
